// Import required modules
import { fetch } from '@cloudflare/durableobjects-fetch-handler';
import { NextFetchEvent } from '@cloudflare/durableobjects-std';

// Define constants for API keys and URLs
const SENDGRID_API_KEY = 'YOUR_SENDGRID_API_KEY';
const STRIPE_SECRET_KEY = 'YOUR_STRIPE_SECRET_KEY';
const SENDGRID_URL = 'https://api.sendgrid.com/v3/mail/send';
const STRIPE_URL = 'https://api.stripe.com/v1/charges';

// Define a function to send email using SendGrid
async function sendEmail(event, name, email) {
  const response = await fetch(SENDGRID_URL, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      Authorization: `Bearer ${SENDGRID_API_KEY}`,
    },
    body: JSON.stringify({
      personalizations: [
        {
          to: [{ email }],
          dynamic_template_data: { name },
        },
      ],
      from: { email: 'your-email@example.com' },
      template_id: 'your-template-id',
    }),
  });

  if (response.ok) {
    return response.json();
  } else {
    throw new Error(`Error sending email: ${response.statusText}`);
  }
}

// Define a function to process payment using Stripe
async function processPayment(event, amount, currency) {
  const response = await fetch(STRIPE_URL, {
    method: 'POST',
    headers: {
      Authorization: `Bearer ${STRIPE_SECRET_KEY}`,
      'Content-Type': 'application/json',
    },
    body: JSON.stringify({
      amount,
      currency,
      source: event.request.json().source,
    }),
  });

  if (response.ok) {
    return response.json();
  } else {
    throw new Error(`Error processing payment: ${response.statusText}`);
  }
}

// Define the main function for the Cloudflare Worker
async function handleRequest(event, { request }) {
  try {
    const data = await request.json();

    // Check if the request is to send an email
    if (data.action === 'send_email') {
      return await sendEmail(event, data.name, data.email);
    }

    // Check if the request is to process a payment
    else if (data.action === 'process_payment') {
      return await processPayment(event, data.amount, data.currency);
    }
  } catch (error) {
    console.error(error);
    throw new Error('Internal Server Error');
  }
}

// Export the main function as the Cloudflare Worker handler
export async function fetchHandler(request: Request): Promise<Response> {
  return handleRequest(request);
}